        << ",\"pass_epoch\":" << pass_epoch << ",\"units\":[";
    for (std::size_t i = 0; i < units.size(); ++i) {
        if (i) {
            out << ',';
        }
        out << units[i].json;
    }
    out << "],\"total_drift_bytes\":" << drift_total << ",\"order_score\":" << weight_total
        << ",\"digest\":\"" << top_digest << "\"}\n";
    std::ofstream file(output_path, std::ios::binary);
    file << out.str();

    // Merge checkpoint: preserve existing entries, update with new
    std::vector<forge::UnitCheckpoint> merged =
        forge_lane_merge_checkpoint(checkpoint, updated_entries, requested_resume);

    // Write checkpoint with pass_epoch
    fs::create_directories(checkpoint_path.parent_path());
    std::ostringstream cp_out;
    cp_out << "{\"schema_version\":" << forge::kSchemaVersion << ",\"lane_token\":\"" << lane_token
           << "\",\"pass_epoch\":" << (pass_epoch + 1) << ",\"units\":[";
    for (size_t i = 0; i < merged.size(); ++i) {
        if (i) {
            cp_out << ',';
        }
        cp_out << "{\"name\":\"" << merged[i].name << "\",\"next_pass\":" << merged[i].next_pass
               << ",\"carry_weight\":" << merged[i].carry_weight << ",\"carry_drift\":"
               << merged[i].carry_drift << '}';
    }
    cp_out << "]}\n";
    std::ofstream cp_file(checkpoint_path, std::ios::binary);
